var existingItems = $input.all();
var existingUrls = new Set();
for (var i = 0; i < existingItems.length; i++) {
  if (existingItems[i].json && existingItems[i].json['詳細ページURL']) {
    existingUrls.add(existingItems[i].json['詳細ページURL']);
  }
}

var BASE_URL = 'https://web.canary-app.jp';
var SEARCH_PARAMS = 'lineStationIds=8822e3d5-5a93-418d-9b19-3a02f53105c7_1dbbea50-46a0-42f1-80d1-1e1f8a5c64fe&lineStationIds=8822e3d5-5a93-418d-9b19-3a02f53105c7_46664ffe-e817-4be9-acea-3a5f0206e8c9&lineStationIds=8822e3d5-5a93-418d-9b19-3a02f53105c7_dcbf594b-e797-4814-9be6-7ad22fb51350&lineStationIds=8822e3d5-5a93-418d-9b19-3a02f53105c7_48ce6849-6478-40da-b5f5-53854b314d3a&lineStationIds=8822e3d5-5a93-418d-9b19-3a02f53105c7_38d2e321-b920-43a7-b0be-a168f0676a2a&prefectureAlias=tokyo&rentMax=140000&isTotalRent=false&optionIds=7299e4c3-ef89-4c8a-a58a-51f8c6ac3149&optionIds=ed465c2d-2d16-4fde-b3c3-43385b4c1250&oldMax=30&duringMax=20&searchType=2&sortType=5';
var UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36';

function extractRoomsFromResponse(iser) {
  var rooms = [];
  if (!iser || !iser.estatesList) return rooms;
  for (var bi = 0; bi < iser.estatesList.length; bi++) {
    var building = iser.estatesList[bi];
    var roomsList = building.roomsList || [];
    for (var ri = 0; ri < roomsList.length; ri++) {
      var r = roomsList[ri];
      var station = '';
      if (r.accessesList && r.accessesList.length > 0) {
        var a = r.accessesList[0];
        station = a.route + ' / ' + a.station + ' 徒歩' + a.during + '分';
      }
      rooms.push({
        id: r.id,
        物件名: r.name || building.name || '',
        住所: r.address || '',
        駅徒歩: station,
        家賃合計: (r.rent || 0) + (r.adminFee || 0),
        詳細ページURL: BASE_URL + '/chintai/rooms/' + r.id + '/',
      });
    }
  }
  return rooms;
}

var results = [];
var allSeenIds = new Set();

// Step 1: ページ1のHTMLを取得して__NEXT_DATA__を抽出
var page1;
try {
  page1 = await this.helpers.httpRequest({
    method: 'GET',
    url: BASE_URL + '/chintai/tokyo/list/?' + SEARCH_PARAMS + '&page=1',
    headers: { 'User-Agent': UA, 'Accept': 'text/html', 'Accept-Language': 'ja' },
  });
} catch (e) {
  return [{ json: { _empty: true, error: 'HTTP取得失敗: ' + e.message } }];
}

var htmlStr = typeof page1 === 'string' ? page1 : String(page1);
var buildId = '';
var totalCount = 0;

var ndIdx = htmlStr.indexOf('"__NEXT_DATA__"');
if (ndIdx === -1) {
  return [{ json: { _empty: true, error: '__NEXT_DATA__が見つかりません' } }];
}

var jsStart = htmlStr.indexOf('>', ndIdx) + 1;
var jsEnd = htmlStr.indexOf('</script>', jsStart);
var nd;
try {
  nd = JSON.parse(htmlStr.substring(jsStart, jsEnd));
} catch (e) {
  return [{ json: { _empty: true, error: 'JSON解析失敗: ' + e.message } }];
}

buildId = nd.buildId || '';
var pp = nd.props && nd.props.pageProps ? nd.props.pageProps : {};
var iser = pp.initialSearchEstatesResponse;

if (!iser || !iser.estatesList) {
  return [{ json: { _empty: true, error: 'initialSearchEstatesResponseが見つかりません', pagePropsKeys: Object.keys(pp).join(',') } }];
}

totalCount = iser.totalCount || 0;

// ページ1のルームを抽出
var page1Rooms = extractRoomsFromResponse(iser);
for (var i = 0; i < page1Rooms.length; i++) {
  if (!allSeenIds.has(page1Rooms[i].id)) {
    allSeenIds.add(page1Rooms[i].id);
    results.push(page1Rooms[i]);
  }
}

// Step 2: _next/dataで残りのページを取得
if (buildId && results.length < totalCount) {
  var perPage = results.length || 20;
  var maxPage = Math.min(Math.ceil(totalCount / perPage), 20);
  for (var page = 2; page <= maxPage; page++) {
    try {
      var dataResp = await this.helpers.httpRequest({
        method: 'GET',
        url: BASE_URL + '/_next/data/' + buildId + '/chintai/tokyo/list.json?' + SEARCH_PARAMS + '&page=' + page,
        headers: { 'User-Agent': UA, 'Accept': 'application/json' },
      });
      var pageData = typeof dataResp === 'string' ? JSON.parse(dataResp) : dataResp;
      var pageIser = pageData.pageProps && pageData.pageProps.initialSearchEstatesResponse;
      if (!pageIser || !pageIser.estatesList || pageIser.estatesList.length === 0) break;
      var pageRooms = extractRoomsFromResponse(pageIser);
      var newCount = 0;
      for (var i = 0; i < pageRooms.length; i++) {
        if (!allSeenIds.has(pageRooms[i].id)) {
          allSeenIds.add(pageRooms[i].id);
          results.push(pageRooms[i]);
          newCount++;
        }
      }
      if (newCount === 0) break;
    } catch (e) {
      break;
    }
  }
}

// JST日付
var now = new Date();
var jstMs = now.getTime() + (9 * 60 + now.getTimezoneOffset()) * 60000;
var jstDate = new Date(jstMs);
var today = jstDate.getFullYear() + '-' + String(jstDate.getMonth() + 1).padStart(2, '0') + '-' + String(jstDate.getDate()).padStart(2, '0');

// 既存物件を除外し新規のみ返す
var newItems = [];
for (var i = 0; i < results.length; i++) {
  var r = results[i];
  if (!existingUrls.has(r['詳細ページURL'])) {
    newItems.push({ json: {
      物件名: r['物件名'],
      住所: r['住所'],
      駅徒歩: r['駅徒歩'],
      家賃合計: r['家賃合計'],
      詳細ページURL: r['詳細ページURL'],
      作成日: today,
      閲覧済み: 'FALSE',
      お気に入り: 'FALSE',
    }});
  }
}

return newItems.length > 0 ? newItems : [{ json: { _empty: true, found: results.length, filtered: existingUrls.size } }];

const items = $input.all();
let rows = '';
for (const item of items) {
  const j = item.json;
  const rent = typeof j.家賃合計 === 'number' ? j.家賃合計.toLocaleString() : String(j.家賃合計);
  rows += '<tr>';
  rows += '<td>' + (j.物件名 || '') + '</td>';
  rows += '<td>' + (j.住所 || '') + '</td>';
  rows += '<td>' + (j.駅徒歩 || '') + '</td>';
  rows += '<td>' + rent + '円</td>';
  rows += '<td><a href="' + (j.詳細ページURL || '') + '">詳細</a></td>';
  rows += '</tr>';
}

const body = '<h2>新規物件が ' + items.length + ' 件見つかりました</h2>'
  + '<table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:14px;">'
  + '<tr style="background:#f0f0f0;"><th>物件名</th><th>住所</th><th>駅徒歩</th><th>家賃合計</th><th>詳細</th></tr>'
  + rows
  + '</table>'
  + '<br><p><a href="https://docs.google.com/spreadsheets/d/1T4eIL7TvDnKImRGXnsk_BpAiquDT4e1jm5lLACYyaiM/edit">スプレッドシートを開く</a></p>';

const output = [{ json: { emailBody: body, count: items.length } }];
return output;
